// COMMAND ROUTER — Routes Telegram messages to the right workflow branch
const message = $input.first().json.message;
const text = message.text || '';
const chatId = message.chat.id;

// Command parsing
let command = 'chat';
let params = {};

if (text.startsWith('/')) {
  const parts = text.split(' ');
  command = parts[0].toLowerCase();
  params.raw = parts.slice(1).join(' ');
} else {
  command = 'chat';
  params.raw = text;
}

// Route commands
const routes = {
  '/start': 'setup',
  '/niche': 'set_niche',
  '/brand': 'set_brand',
  '/research': 'research',
  '/create': 'create_content',
  '/post': 'post_now',
  '/schedule': 'schedule_post',
  '/analytics': 'get_analytics',
  '/report': 'weekly_report',
  '/test': 'ab_test',
  '/monetize': 'monetization',
  '/status': 'status',
  '/settings': 'settings',
  '/help': 'help',
  'chat': 'ai_chat'
};

return [{
  json: {
    command: routes[command] || 'ai_chat',
    rawCommand: command,
    params: params,
    chatId: chatId,
    username: message.from?.username || 'User',
    timestamp: new Date().toISOString()
  }
}];

// SET NICHE — Store the user's niche and begin research
const input = $input.first().json;
const niche = input.params.raw;
const chatId = input.chatId;

if (!niche || niche.length < 3) {
  return [{ json: { error: true, chatId, message: '❌ Please specify a niche! Example: /niche fitness for women over 30' } }];
}

// Store niche (in production, save to database/file)
const nicheData = {
  niche: niche,
  setAt: new Date().toISOString(),
  chatId: chatId,
  status: 'researching'
};

return [{
  json: {
    niche: niche,
    chatId: chatId,
    action: 'auto_research',
    message: `🟢 *Niche Locked In!* 🎯\n\nNiche: *${niche}*\n\nI'm now starting DEEP research on this niche. I'll study:\n🔍 Top competitors\n🧠 Audience psychology\n🎣 Viral hooks\n📊 Trending content\n⏰ Best posting times\n\nThis will take a few minutes. I'll message you when I'm done! 🚀`,
    nicheData: nicheData
  }
}];

// RESEARCH ENGINE — Deep niche research using web search
const input = $input.first().json;
const niche = input.niche || input.params?.raw || 'general';

// Research queries to search
const researchQueries = [
  `best ${niche} instagram accounts 2024 2025`,
  `${niche} instagram carousel viral examples`,
  `${niche} content ideas that go viral`,
  `${niche} audience pain points desires`,
  `${niche} trending topics ${new Date().getFullYear()}`,
  `${niche} instagram hashtags strategy`,
  `${niche} hook examples that work`,
  `${niche} target audience demographics psychology`,
  `${niche} competitors analysis top accounts`,
  `${niche} instagram engagement rate benchmarks`
];

// Return research tasks
return researchQueries.map((query, index) => ({
  json: {
    query: query,
    niche: niche,
    chatId: input.chatId || input.params?.chatId,
    researchIndex: index,
    totalQueries: researchQueries.length
  }
}));

// RESEARCH AGGREGATOR — Compile all research into a knowledge base
const allResults = $input.all();
const niche = allResults[0]?.json?.niche || 'unknown';
const chatId = allResults[0]?.json?.chatId;

// Compile research summary
let knowledgeBase = `# NICHE KNOWLEDGE BASE: ${niche}\n`;
knowledgeBase += `Generated: ${new Date().toISOString()}\n\n`;

allResults.forEach((result, index) => {
  knowledgeBase += `## Research Query ${index + 1}\n`;
  knowledgeBase += `Query: ${result.json.query}\n`;
  knowledgeBase += `Results: ${JSON.stringify(result.json.data || result.json.body || 'No data').substring(0, 500)}\n\n`;
});

// Generate niche summary
const nicheSummary = {
  niche: niche,
  knowledgeBase: knowledgeBase,
  chatId: chatId,
  researchComplete: true,
  timestamp: new Date().toISOString(),
  queriesCompleted: allResults.length
};

return [{ json: nicheSummary }];

// CONTENT GENERATOR — Creates carousel content using AI
const input = $input.first().json;
const niche = input.niche || 'general';
const brand = input.brand || null;
const knowledgeBase = input.knowledgeBase || '';
const chatId = input.chatId;

// Build the AI prompt
const prompt = `You are VIRAL ENGINE — an elite Instagram content creator.

NICHE: ${niche}
BRAND IDENTITY: ${brand ? JSON.stringify(brand) : 'Use modern, clean design with bold typography'}

KNOWLEDGE BASE:
${knowledgeBase.substring(0, 3000)}

Create ONE viral carousel post. Output as JSON:
{
  "slides": [
    {"number": 1, "type": "hook", "headline": "...", "subtext": "...", "bg_color": "#hex", "text_color": "#hex"},
    {"number": 2, "type": "content", "headline": "...", "body": "...", "bg_color": "#hex", "text_color": "#hex"},
    ... (7-10 slides total)
    {"number": 10, "type": "cta", "headline": "...", "body": "...", "bg_color": "#hex", "text_color": "#hex"}
  ],
  "caption": "Full caption with emojis...",
  "hashtags": ["tag1", "tag2", ...],
  "hook_type": "curiosity|stat|question|contrarian",
  "content_pillar": "educational|inspirational|entertainment",
  "best_posting_time": "HH:MM",
  "predicted_engagement": "viral|strong|average"
}

Rules:
- Slide 1 MUST be a scroll-stopping hook
- Use power words, numbers, emotional triggers
- Each slide delivers ONE clear point
- Final slide is a natural CTA
- Caption follows hook-story-value-CTA structure
- Include 20-25 hashtags mixed (broad + medium + niche)
- Colors must be visually stunning and consistent
- Make it look PROFESSIONAL, not AI-generic`;

return [{
  json: {
    prompt: prompt,
    niche: niche,
    chatId: chatId,
    brand: brand
  }
}];

// PARSE AI RESPONSE — Extract carousel JSON from AI output
const input = $input.first().json;
const chatId = input.chatId || $('Content Generator').first().json.chatId;
let carouselData;

try {
  // Parse the AI response
  const response = input.response || input.body || input;
  const text = typeof response === 'string' ? response : JSON.stringify(response);

  // Try to extract JSON from the response
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    carouselData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (e) {
  // Fallback: create a default carousel structure
  carouselData = {
    slides: [
      { number: 1, type: 'hook', headline: 'Stop Scrolling!', subtext: 'This changes everything...', bg_color: '#1a1a2e', text_color: '#ffffff' },
      { number: 2, type: 'content', headline: 'The Problem', body: 'Most people get this wrong...', bg_color: '#16213e', text_color: '#ffffff' },
      { number: 3, type: 'content', headline: 'The Truth', body: 'Here is what actually works...', bg_color: '#0f3460', text_color: '#ffffff' },
      { number: 4, type: 'content', headline: 'Step 1', body: 'Start with this...', bg_color: '#533483', text_color: '#ffffff' },
      { number: 5, type: 'content', headline: 'Step 2', body: 'Then do this...', bg_color: '#2b2d42', text_color: '#ffffff' },
      { number: 6, type: 'content', headline: 'Step 3', body: 'Finally...', bg_color: '#1a1a2e', text_color: '#ffffff' },
      { number: 7, type: 'cta', headline: 'Save This!', body: 'Follow for more tips', bg_color: '#e94560', text_color: '#ffffff' }
    ],
    caption: 'Here are the tips you need to know...',
    hashtags: ['#tips', '#growth', '#viral'],
    hook_type: 'curiosity',
    content_pillar: 'educational'
  };
}

return [{
  json: {
    carousel: carouselData,
    chatId: chatId,
    readyToRender: true
  }
}];

// HTML CAROUSEL RENDERER — Generates HTML for each slide
const input = $input.first().json;
const carousel = input.carousel;
const chatId = input.chatId;

// Generate HTML for each slide
const slidesHtml = carousel.slides.map(slide => {
  const bg = slide.bg_color || '#1a1a2e';
  const textColor = slide.text_color || '#ffffff';
  const headline = slide.headline || 'Slide';
  const body = slide.body || slide.subtext || '';
  const isHook = slide.type === 'hook';
  const isCta = slide.type === 'cta';

  return `
  <div class="slide" style="
    width: 1080px;
    height: 1080px;
    background: ${bg};
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    padding: 80px;
    box-sizing: border-box;
    font-family: 'Inter', 'Helvetica Neue', Arial, sans-serif;
    position: relative;
    overflow: hidden;
  ">
    <!-- Decorative elements -->
    <div style="position:absolute;top:-50px;right:-50px;width:200px;height:200px;border-radius:50%;background:rgba(255,255,255,0.05);"></div>
    <div style="position:absolute;bottom:-80px;left:-80px;width:300px;height:300px;border-radius:50%;background:rgba(255,255,255,0.03);"></div>

    <!-- Slide number indicator -->
    <div style="position:absolute;top:30px;right:40px;font-size:16px;color:rgba(255,255,255,0.4);font-weight:300;letter-spacing:2px;">${slide.number}/${carousel.slides.length}</div>

    <!-- Content -->
    <div style="text-align:center;max-width:900px;z-index:1;">
      <h1 style="
        font-size: ${isHook ? '72px' : '56px'};
        font-weight: ${isHook ? '800' : '700'};
        color: ${textColor};
        margin: 0 0 30px 0;
        line-height: 1.1;
        letter-spacing: -1px;
        ${isHook ? 'text-transform: uppercase;' : ''}
      ">${headline}</h1>
      ${body ? `<p style="
        font-size: ${isHook ? '28px' : '24px'};
        color: rgba(255,255,255,0.8);
        margin: 0;
        line-height: 1.6;
        font-weight: 300;
      ">${body}</p>` : ''}
      ${isCta ? `<div style="margin-top:40px;padding:20px 40px;background:rgba(255,255,255,0.15);border-radius:50px;display:inline-block;font-size:20px;font-weight:600;letter-spacing:1px;">${body}</div>` : ''}
    </div>
  </div>`;
}).join('\n');

// Full HTML document
const fullHtml = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600;700;800;900&display=swap" rel="stylesheet">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #000; }
    .slide { page-break-after: always; }
  </style>
</head>
<body>
  ${slidesHtml}
</body>
</html>`;

return [{
  json: {
    html: fullHtml,
    carousel: carousel,
    chatId: chatId,
    slideCount: carousel.slides.length
  }
}];

// IMAGE CONVERTER — Converts HTML slides to images
// In production: use Puppeteer or a headless browser service
// For free setup: use the html-to-image API or local Puppeteer
const input = $input.first().json;
const carousel = input.carousel;
const chatId = input.chatId;
const html = input.html;

// Save HTML to file for Puppeteer processing
const fs = require('fs');
const path = require('path');

const outputDir = '/tmp/ig-carousel-' + Date.now();
try { fs.mkdirSync(outputDir, { recursive: true }); } catch(e) {}

// Save HTML
fs.writeFileSync(path.join(outputDir, 'carousel.html'), html);

// Save carousel metadata
fs.writeFileSync(path.join(outputDir, 'meta.json'), JSON.stringify({
  carousel: carousel,
  chatId: chatId,
  createdAt: new Date().toISOString()
}, null, 2));

return [{
  json: {
    outputDir: outputDir,
    carousel: carousel,
    chatId: chatId,
    htmlPath: path.join(outputDir, 'carousel.html'),
    status: 'html_ready'
  }
}];

