=cd {{ $json.outputDir }} && node -e "
const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

(async () => {
  const browser = await puppeteer.launch({headless: 'new', args: ['--no-sandbox', '--disable-setuid-sandbox']});
  const page = await browser.newPage();
  await page.setViewport({width: 1080, height: 1080});

  const html = fs.readFileSync('{{ $json.htmlPath }}', 'utf8');
  await page.setContent(html, {waitUntil: 'networkidle0'});

  // Wait for fonts to load
  await page.evaluateHandle('document.fonts.ready');
  await new Promise(r => setTimeout(r, 2000));

  // Capture each slide
  const slides = await page.$$('.slide');
  const imagePaths = [];

  for (let i = 0; i < slides.length; i++) {
    const imgPath = path.join('{{ $json.outputDir }}', `slide_${i + 1}.png`);
    await slides[i].screenshot({path: imgPath, type: 'png'});
    imagePaths.push(imgPath);
  }

  await browser.close();
  console.log(JSON.stringify({images: imagePaths}));
})();
"

