// PREVIEW SENDER — Sends carousel preview to Telegram
const input = $input.first().json;
const carousel = $('Parse AI Response').first().json.carousel;
const chatId = carousel.chatId || input.chatId;

// Build preview message
let preview = `🟢 *New Carousel Created!* 🎨🔥\n\n`;
preview += `📌 *Hook:* ${carousel.slides[0]?.headline}\n`;
preview += `🎣 *Hook Type:* ${carousel.hook_type}\n`;
preview += `📊 *Content Pillar:* ${carousel.content_pillar}\n`;
preview += `📝 *Slides:* ${carousel.slides.length}\n`;
preview += `⏰ *Best Time:* ${carousel.best_posting_time || 'Now'}\n\n`;
preview += `📝 *Caption Preview:*\n${carousel.caption?.substring(0, 300)}...\n\n`;
preview += `🏷️ *Hashtags:* ${carousel.hashtags?.slice(0, 10).join(', ')}...\n\n`;
preview += `Commands:\n`;
preview += `📤 /post — Post now\n`;
preview += `🔄 /create — Generate new one\n`;
preview += `✏️ Edit caption or slides by replying`;\n
return [{
  json: {
    chatId: chatId,
    message: preview,
    carousel: carousel
  }
}];

// IG POSTER — Posts carousel to Instagram via Graph API
const input = $input.first().json;
const carousel = input.carousel;
const chatId = input.chatId;
const imageDir = input.outputDir || '/tmp/ig-carousel-latest';

// Instagram Graph API flow:
// 1. Create container for each image
// 2. Create carousel container
// 3. Publish

const igUserId = process.env.IG_USER_ID;
const accessToken = process.env.IG_ACCESS_TOKEN;

// Step 1: Create media containers for each slide
const imageCount = carousel.slides?.length || 7;
const containerRequests = [];

for (let i = 1; i <= Math.min(imageCount, 10); i++) {
  // In production, these would be real image URLs
  // Images need to be hosted on a public URL
  const imageUrl = `${process.env.PUBLIC_URL || 'https://your-server.com'}/slides/slide_${i}.png`;

  containerRequests.push({
    method: 'POST',
    url: `https://graph.facebook.com/v18.0/${igUserId}/media`,
    body: {
      image_url: imageUrl,
      is_carousel_item: true,
      access_token: accessToken
    }
  });
}

return [{
  json: {
    igUserId: igUserId,
    accessToken: accessToken,
    caption: carousel.caption || 'Check out this post! 🔥',
    containerRequests: containerRequests,
    chatId: chatId,
    hashtags: carousel.hashtags || []
  }
}];

// ANALYTICS TRACKER — Fetches IG post performance
const input = $input.first().json;
const chatId = input.chatId || input.params?.chatId;
const accessToken = process.env.IG_ACCESS_TOKEN;
const igUserId = process.env.IG_USER_ID;

// Fetch recent media
const mediaUrl = `https://graph.facebook.com/v18.0/${igUserId}/media?fields=id,caption,media_type,timestamp,like_count,comments_count&limit=10&access_token=${accessToken}`;

return [{
  json: {
    mediaUrl: mediaUrl,
    chatId: chatId,
    accessToken: accessToken,
    igUserId: igUserId
  }
}];

// ANALYTICS REPORT BUILDER
const input = $input.first().json;
const chatId = input.chatId || $('Analytics Tracker').first().json.chatId;
const media = input.data || [];

// Calculate metrics
let totalLikes = 0;
let totalComments = 0;
let postCount = media.length || 1;
let bestPost = null;
let bestEngagement = 0;

const posts = Array.isArray(media) ? media : [];
posts.forEach(post => {
  const likes = post.like_count || 0;
  const comments = post.comments_count || 0;
  totalLikes += likes;
  totalComments += comments;

  const engagement = likes + comments;
  if (engagement > bestEngagement) {
    bestEngagement = engagement;
    bestPost = post;
  }
});

const avgLikes = Math.round(totalLikes / postCount);
const avgComments = Math.round(totalComments / postCount);

// Build report
let report = `📊 *Analytics Report* 📈\n\n`;
report += `📅 Period: Last ${postCount} posts\n`;
report += `❤️ Total Likes: ${totalLikes}\n`;
report += `💬 Total Comments: ${totalComments}\n`;
report += `📊 Avg Likes/Post: ${avgLikes}\n`;
report += `📊 Avg Comments/Post: ${avgComments}\n\n`;

if (bestPost) {
  report += `🏆 *Top Post:*\n`;
  report += `📝 ${bestPost.caption?.substring(0, 100) || 'No caption'}...\n`;
  report += `❤️ ${bestPost.like_count || 0} likes\n`;
  report += `💬 ${bestPost.comments_count || 0} comments\n\n`;
}

report += `💡 *Insights:*\n`;
if (avgLikes > 100) report += `✅ Strong engagement! Keep it up!\n`;
else report += `📈 Room to grow — let's test new hooks!\n`;

report += `\nCommands:\n✍️ /create — New carousel\n📋 /report — Full weekly report`;

return [{
  json: {
    chatId: chatId,
    message: report,
    metrics: { totalLikes, totalComments, avgLikes, avgComments, postCount }
  }
}];

// MONETIZATION ADVISOR
const input = $input.first().json;
const chatId = input.chatId || input.params?.chatId;
const niche = input.niche || 'your niche';

let report = `💰 *Monetization Strategy* 💎\n\n`;
report += `Based on your niche: *${niche}*\n\n`;

report += `🎯 *Recommended Products:*\n`;
report += `1. 📚 Digital Ebook — $9-29\n`;
report += `   "The Ultimate ${niche} Guide"\n`;
report += `2. 🎓 Online Course — $47-197\n`;
report += `   "Master ${niche} in 30 Days"\n`;
report += `3. 📋 Templates/Presets — $7-37\n`;
report += `   "Done-for-you ${niche} templates"\n`;
report += `4. 🏆 Coaching — $50-300/hour\n`;
report += `   "1-on-1 ${niche} coaching"\n\n`;

report += `🔗 *Setup Steps:*\n`;
report += `1. Create a Linktree or Stan Store (FREE)\n`;
report += `2. Add link to your IG bio\n`;
report += `3. Create a "link in bio" carousel\n`;
report += `4. Soft-promote in value content\n`;
report += `5. Track conversions\n\n`;

report += `💡 *Pro Tips:*\n`;
report += `• Always give value FIRST, sell SECOND\n`;
report += `• Use the 80/20 rule: 80% value, 20% promotion\n`;
report += `• Create urgency with limited offers\n`;
report += `• Test different price points\n`;

report += `\nWant me to create a promotional carousel? Use /create`;

return [{
  json: {
    chatId: chatId,
    message: report
  }
}];

// STATUS CHECK
const input = $input.first().json;
const chatId = input.chatId || input.params?.chatId;

let status = `📡 *VIRAL ENGINE Status* 🟢\n\n`;
status += `🤖 System: ONLINE\n`;
status += `🧠 AI Model: Ollama (Local/Free)\n`;
status += `📱 Telegram: Connected\n`;
status += `📸 Instagram: Connected\n`;
status += `🔍 Research: Active\n`;
