status += `📝 Queue: Ready\n\n`;
status += `Commands:\n`;
status += `✍️ /create — Generate content\n`;
status += `📊 /analytics — View stats\n`;
status += `💰 /monetize — Monetization`;

return [{ json: { chatId, message: status } }];

// AI CHAT — Free-form conversation handler
const input = $input.first().json;
const chatId = input.chatId || input.params?.chatId;
const userMessage = input.params?.raw || input.raw || '';

const prompt = `You are VIRAL ENGINE — an Instagram growth AI assistant.

The user is chatting with you. Respond helpfully, like a smart social media strategist friend.

User message: ${userMessage}

Respond naturally. If they ask about:
- Content ideas → suggest carousel concepts
